solution.javascript:
import { test, expect } from '@playwright/test';

test.describe('Todo Application Tests', () => {

  test.beforeEach(async ({ page }) => {
    await page.goto('https://demo.playwright.dev/todomvc');
  });

  test.afterEach(async ({ page }) => {
    await page.close();
  });

  test('should add a new todo', async ({ page }) => {
    const input = page.getByPlaceholder('What needs to be done?');
    await input.fill('Learn Playwright');
    await input.press('Enter');
    await expect(page.getByText('Learn Playwright')).toBeVisible();
  });

  test('should complete a todo', async ({ page }) => {
    const input = page.getByPlaceholder('What needs to be done?');
    await input.fill('Complete this task');
    await input.press('Enter');

    const todo = page.locator('.todo-list li');
    await todo.locator('.toggle').check();
    await expect(todo).toHaveClass(/completed/);
  });

  test('should delete a todo', async ({ page }) => {
    const input = page.getByPlaceholder('What needs to be done?');
    await input.fill('Delete this task');
    await input.press('Enter');

    const todo = page.locator('.todo-list li');
    await todo.hover();
    await todo.locator('.destroy').click();
    await expect(todo).not.toBeVisible();
  });
});

